#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/stat.h>
#include <fcntl.h>
#include <time.h>

void daemonize() {
 pid_t pid;
 int fd;

 // Step 1: First fork
 pid = fork();
 if (pid < 0) {
 perror("fork failed");
 exit(EXIT_FAILURE);
 }
 if (pid > 0) {
 // Parent exits
 exit(EXIT_SUCCESS);
 }

 // Child continues - become session leader
 if (setsid() < 0) {
 perror("setsid failed");
 exit(EXIT_FAILURE);
 }

 // Step 2: Optional second fork
 pid = fork();
 if (pid < 0) {
 perror("fork failed");
 exit(EXIT_FAILURE);
 }
 if (pid > 0) {
 // First child exits
 exit(EXIT_SUCCESS);
 }

 // Grandchild continues as true daemon

 // Step 3: Change working directory to root
 chdir("/");

 // Step 4: Set file creation mask
 umask(0);

 // Step 5: Close standard file descriptors
 close(STDIN_FILENO);
 close(STDOUT_FILENO);
 close(STDERR_FILENO);

 // Step 6: Redirect to /dev/null
 fd = open("/dev/null", O_RDWR);
 dup2(fd, STDIN_FILENO);
 dup2(fd, STDOUT_FILENO);
 dup2(fd, STDERR_FILENO);
 close(fd);
}

int main() {
 FILE *logfile;

 daemonize();

 // Daemon now runs in background
 logfile = fopen("/tmp/daemon.log", "a");
 if (logfile != NULL) {
 fprintf(logfile, "Daemon started at %s", ctime(&(time_t){time(NULL)}));
 fclose(logfile);
 }

 // Daemon does its work here
 while(1) {
 sleep(30);
 // Periodic tasks
 }

 return 0;
}
